INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('sono', 'Meu bebê dorme muito pouco durante o dia, é normal?', 'Sim, é normal! Cada bebê tem seu ritmo. O importante é que ele dorme bem à noite. Tente criar um ambiente calmo durante o dia também. Se ele está feliz e comendo bem, tudo certo! 💙', 'sono', 'sono', 'sono', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('sono', 'Bebê dorme melhor com luz ou no escuro?', 'No escuro total! A melatonina (hormônio do sono) aumenta no escuro. Tente deixar o quarto bem escurinho, mesmo durante o dia. Produto: **Cortina blackout** para quarto do bebê (ajuda muito!).', 'sono', 'sono', 'sono', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('sono', 'Meu bebê só dorme se eu ficar acordada, posso descansar?', 'Sim! Quando o bebê entrar no sono profundo (uns 20 minutos), você pode sair de perto. Teste colocar a mão no peito dele para ele sentir sua presença mesmo dormindo.', 'sono', 'sono', 'sono', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('sono', 'Bebê recém-nascido pode dormir de barriga para cima?', 'Sim! De barriga para cima é a posição mais segura. Evite almofadas, cobertores ou brinquedos no berço. Só o lençol embaixo dele.', 'sono', 'sono', 'sono', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('sono', 'Quando começa o sono do bebê ficar mais regular?', 'Por volta dos 3 meses, o bebê começa a ter um padrão de sono mais previsível. Mas cada bebê é único! Alguns demoram mais. Paciência, mãe! 💪', 'sono', 'sono', 'sono', 0, 'true');

